current_user = {'id': 1, 'username': 'admin', 'role': 'admin'}

@app.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    if current_user['id'] != request.json.get('user_id'):
        return jsonify({'error': 'Forbidden'}), 403

    user = {
        'id': user_id,
        'email': request.json.get('email', None),
        'username': request.json.get('username', None),
        'role': request.json.get('role', current_user['role']),
        'account_status': request.json.get('account_status', 'active'),
        'subscription_tier': request.json.get('subscription_tier', 'free')
    }

    # Validation
    if user['email'] and not validate_email(user['email']):
        return jsonify({'error': 'Invalid email'}), 400

    db = {'users': [
        {'id': 1, 'email': 'user@example.com', 'username': 'user', 'role': 'user'},
        # Other users...
    ]}

    updated_user = next((u for u in db['users'] if u['id'] == user_id), None)
    if updated_user:
        updated_user.update(user)

        return jsonify({
            'email': updated_user['email'],
            'username': updated_user['username'],
            'role': updated_user['role'],
            'account_status': updated_user['account_status'],
            'subscription_tier': updated_user['subscription_tier']
        }), 200
    else:
        return jsonify({'error': 'User not found'}), 404

def validate_email(email):
    # Basic email validation (simplified)
    return '@' in email and '.' in email

